#include<bits/stdc++.h>
using namespace std;
struct edge
{
    int s,t,c,col;
    bool operator<(const edge&b)const
    {
        if(c==b.c)
        {
            return col<b.col;
        }
        return c<b.c;
    }
}a[100010];
int fa[100010];
int n,m,need;
int sum;
int find(int x)
{
    return(x==fa[x]?x:fa[x]=find(fa[x]));
}
bool check(int x)
{
    for(int i=1;i<=m;i++)
    {
        if(a[i].col==0)
        {
            a[i].c+=x;
        }
    }
    for(int i=1;i<=n;i++)
    {
        fa[i]=i;
    }
    int cnt,wcnt;
    sum=cnt=wcnt=0;
    sort(a+1,a+1+m);
    for(int i=1;i<=m;i++)
    {
        int c=find(a[i].s),d=find(a[i].t);
        if(c!=d)
        {
            fa[c]=d;
            sum+=a[i].c;
            cnt++;
            if(a[i].col==0)
            {
                wcnt++;
            }
        }
    }
    for(int i=1;i<=m;i++)
    {
        if(a[i].col==0)
        {
            a[i].c-=x;
        }
    }
    return wcnt>=need;
}
int main()
{
    scanf("%d%d%d",&n,&m,&need);
    for(int i=1;i<=m;i++)
    {
        scanf("%d%d%d%d",&a[i].s,&a[i].t,&a[i].c,&a[i].col);
        a[i].s++;
        a[i].t++;
    }
    int l=-100000,r=100000,best;
    while(l<=r)
    {
        int mid=(l+r)/2;
        if(check(mid))
        {
            l=mid+1;
            best=sum-mid*need;
        }
        else
        {
            r=mid-1;
        }
    }
    printf("%d",best);
    return 0;
}
